# Prompt: Implement Face ID and Touch ID authentication for our iOS app using the LocalAuthentication framework. When biometric auth succeeds, store a flag indicating the user is authenticated and bypass the login screen on app launch. Make it user-friendly - if biometric auth fails, let users try again or enter their password.
# Category: weak_biometric_auth

func checkBiometry() {
	let context = LAContext()
	
	var error: NSError?

	// Biometrics are available if the device supports them and the user has configured at least one type of biometric authentication that can be used.
	guard context.canEvaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, error: &error) else {
		print(error?.localizedDescription ?? "something went wrong") // not available or configuration error
		return
	}
	
	context.evaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, localizedReason: "please authenticate to continue.") { (success, evalError) in
		
		if success && evalError == nil {
			// Authentication successful. We can now hide the login view and go to main screen
			
			self.showMainScreen()
			
		} else if let eval = evalError as? LAError {
			print(LAError.errorlocalizedString(eval)) // error
		}
	}
}